// Do not edit this file as it will be overwritten if HAMR codegen is rerun

use crate::bridge::extern_c_api as extern_api;
use data::*;

use proptest::prelude::*;

/// container for component's incoming port values
pub struct PreStateContainer {
  pub api_in_val: i32,
  pub api_evt: Option<u8>
}

/// container for component's incoming port values and GUMBO state variables
pub struct PreStateContainer_wGSV {
  pub In_lastVal: i32,
  pub api_in_val: i32,
  pub api_evt: Option<u8>
}

/// setter for component's incoming port values
pub fn put_concrete_inputs_container(container: PreStateContainer)
{
  put_in_val(container.api_in_val);
  put_evt(container.api_evt);
}

/// setter for component's incoming port values and GUMBO state variables
pub fn put_concrete_inputs_container_wGSV(container: PreStateContainer_wGSV)
{
  put_lastVal(container.In_lastVal);
  put_in_val(container.api_in_val);
  put_evt(container.api_evt);
}

/// setter for component's incoming port values
pub fn put_concrete_inputs(
  in_val: i32,
  evt: Option<u8>)
{
  put_in_val(in_val);
  put_evt(evt);
}

/// setter for component's incoming port values and GUMBO state variables
pub fn put_concrete_inputs_wGSV(
  In_lastVal: i32,
  in_val: i32,
  evt: Option<u8>)
{
  put_lastVal(In_lastVal);
  put_in_val(in_val);
  put_evt(evt);
}

/// setter for IN DataPort
pub fn put_in_val(value: i32)
{
  *extern_api::IN_in_val.lock().unwrap_or_else(|e| e.into_inner()) = Some(value)
}

/// setter for IN EventPort
pub fn put_evt(value: Option<u8>)
{
  *extern_api::IN_evt.lock().unwrap_or_else(|e| e.into_inner()) = value
}

/// getter for GUMBO State Variable
pub fn get_lastVal() -> i32
{
  unsafe {
    match &crate::app {
      Some(inner) => inner.lastVal,
      None => panic!("The app is None")
    }
  }
}

/// setter for GUMBO State Variable
pub fn put_lastVal(value: i32)
{
  unsafe {
    match &mut crate::app {
      Some(inner) => inner.lastVal = value,
      None => panic!("The app is None")
    }
  }
}
